INSERT INTO `q` (`id`, `titre`, `position`, `diagnosticmodule_id`, `diagnosticquestiontype_id`, `diagnosticquestioncategorie_id`, `langue_id`, `obligatoire`, `parent`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(850, '1. Projection stratégique Si je vous demande : “Qu’essaie réellement de construire votre entreprise dans les 3 à 5 prochaines années ?” Vous répondez plutôt :', '1', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(859, '10. Solidité du système Si vous vous absentez 30 jours sans intervenir :', '10', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(851, '2. Capacité à renoncer Imaginez qu’un client vous propose un contrat qui rapporte de l’argent rapidement…  mais ce travail ne correspond pas vraiment à ce que vous voulez construire pour votre entreprise. Concrètement, que faites-vous ?', '2', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(852, '3. Allocation des ressources Quand vous devez utiliser votre temps, votre énergie ou votre argent,  comment décidez-vous où les mettre ?', '3', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(853, '4. Rapport au marché Quand les choses changent progressivement autour de vous  (nouveaux concurrents, clients plus exigeants, hausse des prix, nouvelles taxes…) Dans la réalité, que faites-vous ?', '4', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(854, '5. Rapport au risque Avant qu’un problème n’arrive vraiment  (perte d’un gros client, pénalité administrative, difficulté de trésorerie, départ d’un collaborateur clé…) Dans votre manière de diriger, vous êtes plutôt :', '5', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(855, '6. Transmission du cap Si vous demandez à un collaborateur ou associé :  “Qu’est-ce que notre entreprise cherche vraiment à construire ?” Il répondrait plutôt :', '6', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(856, '7. Rapport aux indicateurs Pour savoir si votre entreprise avance vraiment, vous regardez surtout :', '7', 115, 1, 0, 'f9a16e49-d975-4d63-b201-5aee5888ac44', 1, 0, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
