INSERT INTO `r` (`id`, `titre`, `explication`, `position`, `score`, `langue_id`, `diagnosticquestion_id`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(3850, 'Je parle surtout de mes activités actuelles ou de mes problèmes du moment.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 850, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3851, 'J’ai une ambition en tête, mais elle évolue selon les opportunités.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 850, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3852, 'Je décris une direction claire (marché, taille, positionnement), même si tout n’est pas formalisé.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 850, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3853, 'Je formule un cap précis, chiffré et cohérent, avec une trajectoire définie.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 850, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3886, 'L’activité devient instable ou s’arrête.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 859, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3887, 'L’activité continue, mais aucune décision importante n’est prise.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 859, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3888, 'L’activité fonctionne, mais la progression ralentit.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 859, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3889, 'L’entreprise continue d’avancer selon un cap clair que l’équipe connaît.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 859, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3854, 'J’accepte. L’argent passe avant le reste.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 851, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3855, 'J’hésite, mais si cela aide la trésorerie, je prends quand même.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 851, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3856, 'Je réfléchis à l’impact sur mon organisation et sur la direction que je veux donner à mon entreprise.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 851, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3857, 'Je refuse si cela m’éloigne de ma vision, même si l’argent est intéressant.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 851, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3858, 'Je traite d’abord les urgences du moment.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 852, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3859, 'Je choisis surtout ce qui peut rapporter de l’argent rapidement.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 852, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3860, 'Je privilégie ce qui renforce mon activité principale et la rend plus solide.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 852, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3861, 'Je me demande toujours : “Est-ce que cela me rapproche vraiment de ce que je veux construire dans 3 à 5 ans ?”', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 852, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3862, 'Je m’en rends compte seulement quand mes ventes ou mes marges baissent.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 853, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3863, 'Je réagis quand l’impact devient vraiment visible sur mon activité.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 853, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3864, 'Je reste attentif aux signaux (clients, prix, concurrents, réglementation) et j’ajuste progressivement.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 853, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3865, 'J’observe les tendances à l’avance et j’adapte mon offre ou mon organisation avant d’être sous pression.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 853, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3866, 'Je préfère ne pas y penser tant que tout semble aller bien.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 854, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3867, 'Je sais que cela peut arriver, mais je n’ai pas vraiment anticipé comment réagir.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 854, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3868, 'J’ai identifié les risques principaux et je reste vigilant.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 854, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3869, 'J’ai identifié les risques majeurs et préparé des solutions concrètes pour ne pas être pris au dépourvu.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 854, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3870, 'Il décrirait surtout ce qu’on fait au quotidien.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 855, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3871, 'Il parlerait d’objectifs à court terme (ventes, production, livraisons).', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 855, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3872, 'Il expliquerait la direction générale et les objectifs de l’année.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 855, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3873, 'Il saurait expliquer la vision à moyen terme et dire en quoi son travail y contribue.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 855, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3874, 'S’il reste de l’argent en caisse ou si les ventes du mois sont correctes.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 856, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3875, 'Le chiffre d’affaires et quelques chiffres de base.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 856, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3876, 'Les marges, la rentabilité, la satisfaction client et l’évolution régulière.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 856, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3877, 'Quelques indicateurs clés liés à votre vision (croissance, positionnement, rentabilité, part de marché) que vous analysez chaque mois pour décider.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 856, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3878, 'Je continue en espérant que la situation va s’améliorer.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 857, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3879, 'Je change quand je n’ai plus vraiment le choix.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 857, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3880, 'J’analyse les causes et j’ajuste progressivement.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 857, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3881, 'J’utilise les signaux faibles pour ajuster avant que la situation ne devienne critique.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 857, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3882, 'Aucun. Je suis absorbé par l’opérationnel.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 858, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3883, 'Occasionnel, quand l’activité ralentit ou qu’un problème survient.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 858, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3884, 'J’ai un moment régulier pour prendre du recul.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 858, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3885, 'J’ai des revues stratégiques planifiées (mensuelles ou trimestrielles) avec décisions formalisées.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 858, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3890, 'Je dis ce qu’il faut faire. Si ce n’est pas bien fait, je corrige après.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 860, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3891, 'J’explique ce que j’attends, mais je ne vérifie pas vraiment si la personne a bien compris.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 860, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3892, 'Je demande à la personne de reformuler pour être sûr que c’est clair.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 860, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3893, 'J’adapte mon explication selon la personne, je vérifie qu’elle a compris et je précise clairement le résultat attendu.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 860, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3926, 'Les gens écoutent, mais peu de choses changent.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3927, 'Ils comprennent le message, mais l’engagement reste faible.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3928, 'Ils repartent avec une direction claire et des actions à mener.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3929, 'Ils repartent motivés, alignés et prêts à agir concrètement.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 869, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3894, 'Je mets fin à la discussion, c’est moi qui décide.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 861, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3895, 'J’écoute, mais je garde surtout mon point de vue.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 861, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3896, 'J’écoute vraiment pour comprendre ses arguments avant de décider.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 861, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3897, 'Je cherche à transformer le désaccord en une meilleure décision pour tout le monde.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 861, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3898, 'J’y vais comme ça, j’explique mon besoin et j’improvise.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 862, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3899, 'Je prépare quelques arguments, mais sans vraie stratégie.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 862, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3900, 'Je prépare mes arguments, mes chiffres et je clarifie mes limites avant la discussion.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 862, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3901, 'Je prépare mes arguments en pensant aussi aux intérêts de l’autre, et je cherche un accord gagnant pour les deux.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 862, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3902, 'J’annonce la décision. Ils doivent s’adapter.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 863, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3903, 'J’explique rapidement, mais je ne gère pas vraiment les réactions.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 863, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3904, 'J’explique le pourquoi du changement et les bénéfices attendus.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 863, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3905, 'J’explique le contexte, j’écoute les inquiétudes et j’implique l’équipe pour faciliter l’adhésion.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 863, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3906, 'L’information passe surtout par moi. Les autres savent seulement ce qui les concerne directement.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 864, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3907, 'L’information circule, mais de manière informelle, selon les discussions du moment.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 864, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3908, 'Les informations importantes sont partagées régulièrement (réunions, messages clairs, points d’équipe).', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 864, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3909, 'L’information est structurée, claire et accessible. Chacun sait où trouver ce dont il a besoin pour bien décider et agir.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 864, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3910, 'Je travaille surtout seul(e). Je sollicite les autres uniquement en cas d’urgence.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 865, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3911, 'J’appelle certains contacts quand j’ai un problème ou une opportunité ponctuelle.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 865, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3912, 'J’entretiens régulièrement mes relations, même sans besoin immédiat.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 865, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3913, 'Je développe volontairement des alliances utiles à ma vision et je cultive des relations stratégiques sur le long terme.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 865, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3914, 'Parce que vous contrôlez et vérifiez régulièrement.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 866, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3915, 'Parce qu’elle veut éviter les reproches ou les tensions.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 866, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3916, 'Parce qu’elle comprend la direction et voit l’utilité de son travail.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 866, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3917, 'Parce qu’elle adhère au projet, prend des initiatives et défend la vision même en votre absence.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 866, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3918, 'Vous laissez faire, en pensant que cela va se calmer seul.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 867, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3919, 'Vous intervenez quand le problème devient visible ou perturbe le travail.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 867, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3920, 'Vous clarifiez rapidement les faits et donnez un cadre d’échange.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 867, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3921, 'Vous identifiez très tôt les signaux faibles, vous ouvrez le dialogue et transformez la tension en amélioration collective.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 867, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3922, 'Je présente mon besoin et j’espère que cela suffira.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 868, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3923, 'Je défends mon idée avec énergie, mais sans stratégie claire.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 868, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3924, 'Je prépare mes arguments en fonction des intérêts de mon interlocuteur.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 868, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(3925, 'Je construis mon discours autour des enjeux de l’autre, j’anticipe ses objections et je propose une solution alignée avec ses priorités.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 868, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4200, 'Je lui donne la tâche à exécuter, sans autre explication.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 900, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4201, 'Je précise clairement le résultat attendu et le délai.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 900, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4202, 'J’explique le résultat attendu, le délai et l’impact de cette mission sur l’activité actuelle.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 900, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4203, 'Je relie la mission au cap stratégique et je vérifie qu’il comprend sa marge de décision et les critères de réussite.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 900, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4236, 'Celui/celle qui fait à la place des autres pour éviter les erreurs.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 909, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4237, 'Celui/celle qui contrôle, corrige et vérifie en permanence.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 909, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4238, 'Celui/celle qui explique, cadre et aide les autres à progresser.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 909, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4239, 'Celui/celle qui structure, délègue et développe une équipe capable d’avancer même en son absence.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 909, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4204, 'Non, chacun fait un peu de tout selon les urgences.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 901, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4205, 'Chacun connaît sa mission principale, mais les limites restent floues.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 901, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4206, 'Les responsabilités sont écrites et chacun sait ce qu’il doit livrer.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 901, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4207, 'Chaque membre connaît son périmètre de décision et agit sans devoir vous consulter en permanence.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 901, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4208, 'Je décide seul(e) et j’informe ensuite l’équipe.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 902, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4209, 'Je demande l’avis des autres, mais la décision est déjà presque prise.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 902, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4210, 'J’écoute réellement les avis avant de trancher.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 902, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4211, 'Je délègue certaines décisions quand c’est possible et j’aide les autres à apprendre à décider par eux-mêmes.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 902, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4212, 'Je considère que c’est normal, il est payé pour ça.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4213, 'Je le félicite quand j’y pense.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4214, 'Je souligne ses progrès et je lui donne plus de responsabilités.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4215, 'Je cherche volontairement à le faire monter en compétence, même si cela signifie qu’il peut un jour me dépasser sur certains sujets.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 903, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
