(4289, 'Je reconnais que je me suis trompé(e), mais je préfère passer rapidement à autre chose.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 922, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
