(4299, 'J’identifie les risques majeurs, j’évalue leur impact possible et je prévois à l’avance quoi faire si l’un d’eux survient.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 924, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4300, 'Je passe à autre chose. Si personne ne se plaint, je considère que c’est bon.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 925, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4301, 'Je regarde rapidement si “ça semble marcher”, sans suivi précis.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 925, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4302, 'Je vérifie les résultats concrets par rapport à ce que j’attendais (délais, coûts, performance).', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 925, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4303, 'J’analyse les résultats, les écarts éventuels, et j’améliore ma façon de décider pour la prochaine fois.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 925, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4304, 'Souvent retardées par hésitation ou peur de se tromper.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 926, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4305, 'Prises rapidement sous pression, mais parfois sans analyse suffisante.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 926, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4306, 'Réfléchies, structurées et assumées, même si elles sont difficiles.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 926, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4307, 'Réfléchies, alignées avec la stratégie long terme et assumées fermement, même sous pression ou en cas d’opposition.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 926, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4308, 'Je choisis l’option la plus simple ou la plus rapide pour avancer.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 927, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4309, 'Je prends celle qui me semble la moins risquée à court terme, même si le gain est limité.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 927, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4310, 'Je compare clairement les avantages, les inconvénients et les impacts de chaque option avant de trancher.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 927, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4311, 'J’évalue les impacts financiers, humains, opérationnels et stratégiques avant d’arbitrer.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 927, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4312, 'Mettre en avant les circonstances ou les erreurs des autres pour expliquer ce qui s’est passé.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 928, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
