(4314, 'Assumer clairement votre décision et ses conséquences.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 928, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4315, 'Assumer publiquement, analyser ce qui doit évoluer et transformer l’erreur en apprentissage pour l’équipe.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 928, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4320, 'Je m’en rends compte quand ma trésorerie baisse ou que les ventes chutent déjà.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 930, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4321, 'Je vois que ça change, mais j’attends de sentir un vrai impact avant d’agir.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 930, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4322, 'Je surveille régulièrement les prix, les comportements clients et les décisions publiques pour ajuster progressivement.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 930, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4323, 'J’essaie de prévoir ce qui peut changer (coûts, concurrence, réglementation) et j’adapte mon organisation avant que cela ne me pénalise.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 930, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4356, 'Celui/celle qui subit et essaie de limiter les dégâts.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 939, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4357, 'Celui/celle qui s’adapte quand la pression devient forte.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 939, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4358, 'Celui/celle qui ajuste avec méthode et calme.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 939, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
