(4324, 'Je continue pareil en espérant que le marché va repartir.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 931, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4325, 'Je change quelque chose rapidement pour “voir si ça marche”.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 931, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4326, 'Je prends le temps d’analyser ce qui bloque avant de modifier.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 931, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
