(4333, 'Maintenir la décision sans vraiment traiter les objections.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 933, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
