(4336, 'Je change seulement quand la situation devient critique.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 934, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
