(4340, 'Je passe rapidement à autre chose.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 935, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4341, 'Je regarde si “ça semble fonctionner”, sans suivi structuré.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 935, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
