(4345, 'Je m’adapte dans l’urgence pour limiter les dégâts.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 936, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4346, 'J’analyse l’impact réel et j’ajuste progressivement mon organisation.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 936, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
