(4349, 'J’explique rapidement, mais sans gérer les réactions ou inquiétudes.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 937, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4350, 'J’explique le pourquoi, les impacts concrets et ce que chacun doit faire.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 937, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
