(4353, 'On commence avec motivation, puis l’élan retombe faute de suivi clair.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 938, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4354, 'Il y a des étapes définies, des responsables identifiés et un suivi régulier.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 938, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4355, 'Le changement est préparé, suivi, ajusté et intégré durablement dans les habitudes.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 938, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4360, '“Parce que c’est moins cher” ou “c’est juste à côté.”', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 940, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4361, '“Parce qu’on se connaît depuis longtemps.”', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 940, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4362, '“Parce que son produit ou service répond bien à mon besoin.”', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 940, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
