(4397, 'Je vends ce que je sais déjà produire.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 949, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4398, 'J’adapte ce que je produis à ce que le marché demande.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 949, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4399, 'J’identifie une opportunité claire (besoin mal servi, niche précise, problème spécifique), puis je conçois une offre parfaitement alignée avec cette opportunité.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 949, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
