(4365, 'J’écoute surtout quand il y a un problème ou une plainte.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 941, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4366, 'Je pose régulièrement des questions pour mieux comprendre leurs attentes.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 941, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
