(4368, '“Il est parti pour moins cher ailleurs.”', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 942, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4369, 'Je le laisse partir sans chercher à comprendre.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 942, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4370, 'Je cherche à connaître la raison précise de son départ.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 942, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4371, 'J’analyse les causes, j’ajuste si nécessaire mon offre ou mon service et je mets en place des actions pour éviter que cela se reproduise.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 942, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4372, 'Je regarde les prix des concurrents et je m’aligne.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 943, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4373, 'Je fixe un prix qui me permet de vendre vite, même si la marge est faible.', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 943, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4374, 'Je calcule précisément mes coûts et j’ajoute une marge cohérente.', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 943, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25');
INSERT INTO `r` (`id`, `titre`, `explication`, `position`, `score`, `langue_id`, `diagnosticquestion_id`, `spotlight`, `etat`, `created_at`, `updated_at`) VALUES
(4375, 'Je fixe mes prix en fonction de la valeur perçue par le client et du positionnement stratégique que je veux occuper sur le marché.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 943, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4376, 'Je propose la même chose que les autres.', NULL, 1, '1', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 944, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4377, 'J’essaie d’être “un peu meilleur” (plus rapide, plus poli, un peu moins cher).', NULL, 2, '2', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 944, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4378, 'J’ai un élément distinctif clair (qualité, spécialisation, expertise, service…).', NULL, 3, '3', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 944, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4379, 'Mon positionnement est clair et assumé : je sais exactement pour qui je suis fait et pour qui je ne suis pas fait.', NULL, 4, '4', 'f9a16e49-d975-4d63-b201-5aee5888ac44', 944, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
