(4575, 'J\'optimise mon BFR en exigeant des acomptes, en réduisant mes stocks et en négociant mes délais fournisseurs.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 993, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4576, 'Je confonds mon bénéfice comptable avec l\'argent disponible en banque.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 994, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4577, 'Je ne sais pas comment calculer ma CAF ni à quoi elle sert précisément.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 994, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4578, 'Je connais ma CAF et je l\'utilise pour rembourser mes emprunts sans mettre l\'entreprise en danger.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 994, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4579, 'Je maximise ma CAF pour financer mes nouveaux investissements et garantir mon autonomie financière.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 994, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4580, 'Je ne demande rien aux banques par peur ou par manque de garanties.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 995, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4581, 'Je n\'emprunte que lorsque je n\'ai plus le choix, souvent en position de faiblesse.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 995, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4582, 'J\'utilise le crédit pour mes investissements durables, en respectant la règle des 70% de financement maximum.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 995, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4583, 'Je pratique l\'endettement stratégique : j\'emprunte quand le rendement attendu est bien supérieur au coût du crédit.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 995, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4584, 'Je l\'utilise principalement pour mes dépenses personnelles ou des achats \"plaisir\".', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 996, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4585, 'Je laisse l\'argent dormir sur le compte sans savoir s\'il vaut mieux investir ou épargner.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 996, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4586, 'Je réinvestis une partie de mes gains pour maintenir mon outil de production en état.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 996, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4587, 'Je réinvestis massivement (jusqu\'à 70%) dans de nouveaux actifs pour créer un \"effet boule de neige\".', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 996, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4588, 'Sur mon intuition et mon ressenti du terrain uniquement.', NULL, 1, '1', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 997, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4589, 'Sur quelques chiffres isolés (Chiffre d\'affaires de la semaine) sans vision globale.', NULL, 2, '2', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 997, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4590, 'J\'ai un tableau de bord simple avec une dizaine d\'indicateurs clés que je mets à jour chaque mois.', NULL, 3, '3', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 997, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
(4591, 'Je ne décide rien sans chiffres fiables : je compare le \"Réel\" au \"Budget\" pour corriger immédiatement mes trajectoires.', NULL, 4, '4', 'f10a16e49-d975-4d63-b201-5aee5888ac44', 997, 0, 1, '2026-03-02 15:32:25', '2026-03-02 15:32:25'),
